import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

describe('truncateContent', () => {
  beforeEach(() => {
    // Setup if needed
  });

  afterEach(() => {
    // Cleanup if needed
  });

  it('should truncate content that exceeds maxLength', () => {
    const content = 'This is a very long string that definitely exceeds the default maximum length of eighty characters and should be truncated';
    const result = truncateContent(content, 50);
    expect(result.length).toBeLessThanOrEqual(50);
    expect(result).toBe('This is a very long string that definitely exceeds the d');
  });

  it('should handle content exactly at or below maxLength', () => {
    const content = 'Short text';
    const result = truncateContent(content, 50);
    expect(result).toBe(content);
    expect(result).toBe('Short text');
  });

  it('should handle null, undefined, and empty values', () => {
    expect(truncateContent(null)).toBe('');
    expect(truncateContent(undefined)).toBe('');
    expect(truncateContent('')).toBe('');
    expect(truncateContent('', 0)).toBe('');
  });
});

